// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// place any helper functions or sub-components above Component

function useComponent(props: Props) {
  // Memoize weather icon mapping
  const getWeatherIcon = useCallback((condition: string): string => {
    // If input is already an emoji (single character), return it as-is
    if (condition && condition.length <= 2) return condition;
    const conditionLower = condition.toLowerCase();
    if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
    if (conditionLower.includes('cloudy') || conditionLower.includes('overcast')) return '☁️';
    if (conditionLower.includes('rainy') || conditionLower.includes('rain')) return '🌧️';
    if (conditionLower.includes('snow')) return '❄️';
    if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
    if (conditionLower.includes('wind')) return '💨';
    if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
    return '🌤️'; // default
  }, []);

  return { getWeatherIcon };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* HEADER */}
        <Stack gap={8} align="center" justify="center">
          <Heading level={1}>{props.city}</Heading>
          <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Weather Forecast
          </Text>
        </Stack>

        {/* MAIN WEATHER CARD */}
        <Card shadow="md" padding={32} radius="lg">
          <Stack gap={24}>
            {/* Current Conditions */}
            <Stack gap={16} align="center" justify="center">
              <Icon name={state.getWeatherIcon(props.condition)} size={80} />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {props.condition}
              </Text>
            </Stack>

            {/* Temperature - Large and Prominent */}
            <Box
              style={{
                textAlign: 'center',
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-onSurface, #18181b)',
              }}
            >
              {props.temperature}° {props.unit}
            </Box>

            {/* Divider */}
            <Divider orientation="horizontal" margin={8} />

            {/* Humidity and Wind Speed */}
            <Row gap={32} justify="center" align="center">
              <Stack gap={8} align="center">
                <Icon name="droplets" size={24} color="var(--ggui-color-primary-600, #0284c7)" />
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Humidity
                </Text>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.humidity}%
                </Text>
              </Stack>

              <Stack gap={8} align="center">
                <Icon name="wind" size={24} color="var(--ggui-color-success-600, #16a34a)" />
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Wind Speed
                </Text>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.windSpeed} m/s
                </Text>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-DAY FORECAST */}
        <Stack gap={12}>
          <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
            5-Day Forecast
          </Heading>
          <Box style={{ overflowX: 'auto', display: 'flex', gap: 'var(--ggui-spacing-2, 8px)' }}>
            {props.forecast && props.forecast.length > 0 ? (
              props.forecast.map((day, index) => (
                <Card
                  key={index}
                  shadow="sm"
                  padding={16}
                  radius="md"
                  style={{
                    flex: '0 0 auto',
                    minWidth: '120px',
                    textAlign: 'center',
                  }}
                >
                  <Stack gap={12} align="center">
                    <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                      {day.day || `Day ${index + 1}`}
                    </Text>
                    <Icon
                      name={state.getWeatherIcon(day.icon || 'clear')}
                      size={32}
                    />
                    <Stack gap={4} align="center">
                      <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)" weight="semibold">
                        {day.high !== undefined ? `${day.high}°` : 'N/A'}
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {day.low !== undefined ? `${day.low}°` : 'N/A'}
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              ))
            ) : (
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No forecast data available
              </Text>
            )}
          </Box>
        </Stack>
      </Stack>
    </Container>
  );
}

