// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// place any helper functions or sub-components above Component

function useComponent(props: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({ name: '', email: '', satisfaction: 0, features: [] as string[], comments: '' });
  const [errors, setErrors] = useState<{ name?: string; email?: string; step2?: string; step3?: string }>({});

  const submit = useAction<ActionSubmitPayload>('submit');

  const validateEmail = useCallback((email: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }, []);

  const validateStep1 = useCallback(() => {
    const newErrors: typeof errors = {};
    if (!formData.name.trim()) newErrors.name = 'Name is required';
    if (!formData.email.trim()) newErrors.email = 'Email is required';
    else if (!validateEmail(formData.email)) newErrors.email = 'Invalid email format';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [formData, validateEmail]);

  const isStep1Valid = !errors.name && !errors.email && formData.name.trim() && formData.email.trim() && validateEmail(formData.email);
  const isStep2Valid = formData.satisfaction > 0;
  const isStep3Valid = formData.features.length > 0;

  const handleNext = useCallback(() => {
    if (currentStep === 1 && !validateStep1()) return;
    if (currentStep === 2) {
      if (formData.satisfaction === 0) {
        setErrors((prev) => ({ ...prev, step2: 'Please select a satisfaction rating' }));
        return;
      }
      setErrors((prev) => ({ ...prev, step2: undefined }));
    }
    if (currentStep === 3) {
      if (formData.features.length === 0) {
        setErrors((prev) => ({ ...prev, step3: 'Please select at least one feature' }));
        return;
      }
      setErrors((prev) => ({ ...prev, step3: undefined }));
    }
    if (currentStep < 5) setCurrentStep(currentStep + 1);
  }, [currentStep, validateStep1, formData.satisfaction, formData.features.length]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) setCurrentStep(currentStep - 1);
  }, [currentStep]);

  const handleSubmit = useCallback(() => {
    submit(formData);
  }, [formData, submit]);

  return { currentStep, setCurrentStep, formData, setFormData, errors, setErrors, handleNext, handleBack, handleSubmit, isStep1Valid, isStep2Valid, isStep3Valid, validateStep1 };
}

export default function Component(props: Props) {
  const { currentStep, formData, setFormData, errors, setErrors, handleNext, handleBack, handleSubmit, isStep1Valid, isStep2Valid, isStep3Valid, validateStep1 } = useComponent(props);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* PROGRESS BAR */}
        <Stack gap={8}>
          <Text variant="label">Step {currentStep} of 4</Text>
          <Progress value={((currentStep - 1) / 4) * 100} max={100} size="md" />
        </Stack>

        {/* STEP 1: NAME & EMAIL */}
        {currentStep === 1 && (
          <Stack gap={16}>
            <Heading level={2}>Your Information</Heading>
            <Input label="Name" placeholder="Enter your name" value={formData.name} onChange={(v) => { setFormData({...formData, name: v}); setErrors({}); }} error={errors.name} required />
            <Input label="Email" type="email" placeholder="Enter your email" value={formData.email} onChange={(v) => { setFormData({...formData, email: v}); setErrors({}); }} error={errors.email} required />
          </Stack>
        )}

        {/* STEP 2: SATISFACTION */}
        {currentStep === 2 && (
          <Stack gap={16}>
            <Heading level={2}>How satisfied are you?</Heading>
            <RadioGroup label="Satisfaction Rating" value={String(formData.satisfaction)} onChange={(v) => { setFormData({...formData, satisfaction: parseInt(v)}); setErrors({}); }} options={(props.satisfactionLabels ?? []).map((label, i) => ({ value: String(i + 1), label }))} direction="horizontal" error={errors.step2} />
          </Stack>
        )}

        {/* STEP 3: FEATURES */}
        {currentStep === 3 && (
          <Stack gap={16}>
            <Heading level={2}>What features interest you?</Heading>
            {errors.step3 && <Alert variant="error" title="Validation Error">{errors.step3}</Alert>}
            <Stack gap={8}>
              {(props.featureOptions ?? []).map((feature) => (
                <Checkbox key={feature} label={feature} checked={formData.features.includes(feature)} onChange={(checked) => { setFormData({...formData, features: checked ? [...formData.features, feature] : (formData.features ?? []).filter(f => f !== feature)}); setErrors({}); }} />
              ))}
            </Stack>
          </Stack>
        )}

        {/* STEP 4: COMMENTS */}
         {currentStep === 4 && (
           <Stack gap={16}>
             <Heading level={2}>Additional Comments</Heading>
             <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">(Optional)</Text>
             <Stack gap={8}>
               <TextArea label="Comments" placeholder="Share any additional thoughts..." value={formData.comments} onChange={(v) => setFormData({...formData, comments: v.slice(0, 500)})} maxLength={500} showCount rows={6} />
               <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{formData.comments.length}/500</Text>
             </Stack>
           </Stack>
         )}

        {/* STEP 5: REVIEW */}
        {currentStep === 5 && (
          <Stack gap={16}>
            <Heading level={2}>Review Your Answers</Heading>
            <Card shadow="md" padding={16}>
              <Stack gap={12}>
                <Stack gap={4}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                  <Text>{formData.name}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                  <Text>{formData.email}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction</Text>
                   <Text>{formData.satisfaction > 0 && props.satisfactionLabels ? props.satisfactionLabels[formData.satisfaction - 1] : 'Not provided'}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Interested Features</Text>
                  <Stack gap={4}>
                    {formData.features.map((f) => <Badge key={f} variant="primary">{f}</Badge>)}
                  </Stack>
                </Stack>
                {formData.comments && (
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
                    <Text>{formData.comments}</Text>
                  </Stack>
                )}
              </Stack>
            </Card>
          </Stack>
        )}

        {/* NAVIGATION */}
        <Row gap={8} justify="end">
          {currentStep > 1 && <Button variant="secondary" onClick={handleBack}>Back</Button>}
          {currentStep < 5 && <Button variant="primary" onClick={handleNext} disabled={currentStep === 1 ? !isStep1Valid : currentStep === 2 ? !isStep2Valid : currentStep === 3 ? !isStep3Valid : false}>Next</Button>}
          {currentStep === 5 && <Button variant="primary" onClick={handleSubmit}>Submit</Button>}
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Task card component
function TaskCard({
  task,
  isEditing,
  editingTitle,
  onStartEdit,
  onSaveEdit,
  onCancelEdit,
  onMove,
  onDelete,
  allColumns,
  setEditingTitle,
}: {
  task: Props['tasks'][0];
  isEditing: boolean;
  editingTitle: string;
  onStartEdit: (id: string, title: string) => void;
  onSaveEdit: (id: string) => void;
  onCancelEdit: () => void;
  onMove: (taskId: string, targetColumn: string) => void;
  onDelete: (taskId: string) => void;
  allColumns: Props['columns'];
  setEditingTitle: (title: string) => void;
}) {
  const getPriorityColor = (priority?: string): 'primary' | 'warning' | 'error' | 'default' => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'primary';
      default:
        return 'default';
    }
  };

  const priorityLabel = task.priority ? task.priority.charAt(0).toUpperCase() + task.priority.slice(1) : 'Normal';

  return (
    <Card shadow="sm" padding={12} radius="md">
      <Stack gap={8}>
        {isEditing ? (
          <Stack gap={6}>
            <Input
              label="Task title"
              value={editingTitle}
              onChange={setEditingTitle}
              size="sm"
            />
            <Row gap={4}>
              <Button size="xs" variant="primary" onClick={() => onSaveEdit(task.id!)}>
                Save
              </Button>
              <Button size="xs" variant="ghost" onClick={onCancelEdit}>
                Cancel
              </Button>
            </Row>
          </Stack>
        ) : (
          <>
            <Text as={Clickable} onClick={() => onStartEdit(task.id!, task.title!)} variant="body" weight="medium">
              {task.title}
            </Text>
            <Row gap={6} align="center">
              {task.priority && <Badge variant={getPriorityColor(task.priority)} size="sm">{priorityLabel}</Badge>}
              {task.assignee && <Avatar name={task.assignee} size="sm" />}
            </Row>
            {task.dueDate && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Due: {task.dueDate}</Text>}
            <Row gap={4}>
              <Dropdown
                trigger={<Button size="xs" variant="ghost">Move</Button>}
                options={allColumns.map((col) => ({ value: col.id || '', label: col.name || '' }))}
                value={task.column || ''}
                onChange={(col) => onMove(task.id!, col)}
                placement="bottom-start"
              />
              <Button size="xs" variant="ghost" onClick={() => onDelete(task.id!)}>
                <Icon name="trash" size={14} />
              </Button>
            </Row>
          </>
        )}
      </Stack>
    </Card>
  );
}

// Column component
function KanbanColumn({
  columnId,
  columnName,
  tasks,
  editingTaskId,
  editingTitle,
  showAddForm,
  newTaskTitle,
  newTaskPriority,
  onStartEdit,
  onSaveEdit,
  onCancelEdit,
  onMove,
  onDelete,
  onAddTask,
  onShowAddForm,
  allColumns,
  setEditingTitle,
  setNewTaskTitle,
  setNewTaskPriority,
}: {
  columnId: string;
  columnName: string;
  tasks: Props['tasks'];
  editingTaskId: string | null;
  editingTitle: string;
  showAddForm: string | null;
  newTaskTitle: string;
  newTaskPriority: 'low' | 'medium' | 'high';
  onStartEdit: (id: string, title: string) => void;
  onSaveEdit: (id: string) => void;
  onCancelEdit: () => void;
  onMove: (taskId: string, targetColumn: string) => void;
  onDelete: (taskId: string) => void;
  onAddTask: (columnId: string) => void;
  onShowAddForm: (columnId: string | null) => void;
  allColumns: Props['columns'];
  setEditingTitle: (title: string) => void;
  setNewTaskTitle: (title: string) => void;
  setNewTaskPriority: (priority: 'low' | 'medium' | 'high') => void;
}) {
  return (
    <Card shadow="md" padding={12} radius="md" border>
      <Stack gap={12}>
        {/* Column Header */}
        <Stack gap={8}>
          <Text variant="label" weight="semibold">{columnName} ({tasks.length})</Text>
        </Stack>

        {/* Task List */}
        <Stack gap={8}>
          {tasks.map((task) => (
            <TaskCard
              key={task.id}
              task={task}
              isEditing={editingTaskId === task.id}
              editingTitle={editingTitle}
              onStartEdit={onStartEdit}
              onSaveEdit={onSaveEdit}
              onCancelEdit={onCancelEdit}
              onMove={onMove}
              onDelete={onDelete}
              allColumns={allColumns}
              setEditingTitle={setEditingTitle}
            />
          ))}
        </Stack>

        {/* Add Task Form */}
        {showAddForm === columnId ? (
          <Stack gap={6} style={{ background: 'var(--ggui-color-surfaceVariant, #f4f4f5)', padding: 'var(--ggui-spacing-2, 8px)', border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)', borderRadius: 'var(--ggui-shape-radius-md, 8px)' }}>
            <Input
              label="Task title"
              placeholder="Enter task title..."
              value={newTaskTitle}
              onChange={setNewTaskTitle}
              size="sm"
            />
            <Select
              label="Priority"
              value={newTaskPriority}
              onChange={(val) => setNewTaskPriority(val as 'low' | 'medium' | 'high')}
              options={[
                { value: 'low', label: 'Low' },
                { value: 'medium', label: 'Medium' },
                { value: 'high', label: 'High' },
              ]}
              size="sm"
            />
            <Row gap={4}>
              <Button size="xs" variant="primary" onClick={() => onAddTask(columnId)}>
                Create
              </Button>
              <Button size="xs" variant="ghost" onClick={() => onShowAddForm(null)}>
                Cancel
              </Button>
            </Row>
          </Stack>
        ) : (
          <Button
            size="sm"
            variant="outline"
            fullWidth
            onClick={() => onShowAddForm(columnId)}
          >
            + Add Task
          </Button>
        )}
      </Stack>
    </Card>
}
function useComponent(props: Props) {
  // State for task management
  const [tasks, setTasks] = useState(props.tasks || []);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [showAddForm, setShowAddForm] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // Sync stream updates to local state
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'create' && task) {
        setTasks((prev) => [...prev, task]);
      } else if (action === 'move' && task) {
        setTasks((prev) => prev.map((t) => (t.id === task.id ? { ...t, column: task.column } : t)));
      } else if (action === 'edit' && task) {
        setTasks((prev) => prev.map((t) => (t.id === task.id ? task : t)));
      } else if (action === 'delete' && task) {
        setTasks((prev) => prev.filter((t) => t.id !== task.id));
      }
    }
  }, [taskChanged.latest]);

  // Computed: group tasks by column
  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, typeof tasks> = {};
    props.columns.forEach((col) => {
      grouped[col.id || ''] = tasks.filter((t) => t.column === col.id);
    });
    return grouped;
  }, [tasks, props.columns]);

  // Computed: summary stats
  const stats = useMemo(() => {
    const total = tasks.length;
    const completed = tasks.filter((t) => t.column === 'done').length;
    return { total, completed };
  }, [tasks]);

  // Handlers
  const handleStartEdit = useCallback((taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle);
  }, []);

  const handleSaveEdit = useCallback((taskId: string) => {
    if (editingTitle.trim()) {
      setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, title: editingTitle } : t)));
      taskUpdate({ action: 'edit', taskId, data: { column: tasks.find((t) => t.id === taskId)?.column || 'todo' } });
      setEditingTaskId(null);
      setEditingTitle('');
    }
  }, [editingTitle, taskUpdate, tasks]);

  const handleCancelEdit = useCallback(() => {
    setEditingTaskId(null);
    setEditingTitle('');
  }, []);

  const handleMoveTask = useCallback((taskId: string, targetColumn: string) => {
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: targetColumn } : t)));
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
  }, [taskUpdate]);

  const handleAddTask = useCallback((columnId: string) => {
    if (newTaskTitle.trim()) {
      const newTask = {
        id: `task-${Date.now()}`,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
        assignee: '',
        dueDate: '',
      };
      setTasks((prev) => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setShowAddForm(null);
    }
  }, [newTaskTitle, newTaskPriority, taskUpdate]);

  const handleDeleteTask = useCallback((taskId: string) => {
    setTasks((prev) => prev.filter((t) => t.id !== taskId));
    taskUpdate({ action: 'delete', taskId, data: { column: '' } });
  }, [taskUpdate]);

  return {
    tasks,
    editingTaskId,
    editingTitle,
    showAddForm,
    newTaskTitle,
    newTaskPriority,
    tasksByColumn,
    stats,
    handleStartEdit,
    handleSaveEdit,
    handleCancelEdit,
    handleMoveTask,
    handleAddTask,
    handleDeleteTask,
    setEditingTitle,
    setNewTaskTitle,
    setNewTaskPriority,
    setShowAddForm,
    taskUpdate,
    taskChanged,
  };
}

