function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements by name or symbol
  const filteredElements = useMemo(() => {
    const els = props.elements || [];
    if (!searchQuery.trim()) return els;
    const query = searchQuery.toLowerCase();
    return els.filter(el =>
      (el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query))
    );
  }, [searchQuery, props.elements]);

  const handleSearch = useCallback((value: string) => {
    setSearchQuery(value);
    setSelectedElement(null);
  }, []);

  const handleElementClick = useCallback((element: typeof props.elements[0]) => {
    setSelectedElement(element);
  }, []);

  const getCategoryColor = useCallback((category?: string) => {
    if (!category) return CATEGORY_COLORS['other'];
    return CATEGORY_COLORS[category] || CATEGORY_COLORS['other'];
  }, []);

  const getCategoryTextColor = useCallback((category?: string) => {
    if (!category) return CATEGORY_TEXT_COLORS['other'];
    return CATEGORY_TEXT_COLORS[category] || CATEGORY_TEXT_COLORS['other'];
  }, []);

  return {
    searchQuery,
    handleSearch,
    filteredElements,
    selectedElement,
    handleElementClick,
    getCategoryColor,
    getCategoryTextColor,
  };
}

