        <Card shadow="sm" padding={16} radius="md" border>
          <Stack gap={12} direction="horizontal" align="center">
            {/* Quantity Selector */}
            <Stack gap={8} direction="horizontal" align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Quantity:
              </Text>
              <Button
                variant="outline"
                size="sm"
                onClick={state.decrementQuantity}
                disabled={state.quantity <= 1}
              >
                −
              </Button>
              <Text
                variant="label"
                align="center"
                style={{ minWidth: '40px' }}
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {state.quantity}
              </Text>
              <Button
                variant="outline"
                size="sm"
                onClick={state.incrementQuantity}
                disabled={state.quantity >= state.maxQuantity}
              >
                +
              </Button>
            </Stack>

            <Spacer size="flex" />

            {/* Add to Cart Button */}
            <Button
              variant="primary"
              size="md"
              onClick={state.handleAddToCart}
              disabled={state.isOutOfStock}
              leftIcon={<Icon name="shopping-cart" size={18} />}
            >
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    );
  }

