function useComponent(props: Props) {
  // State for messages and input
  const [messages, setMessages] = useState(props.messages);
  const [inputValue, setInputValue] = useState('');
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, scrollToBottom]);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator
  useEffect(() => {
    if (typing.latest) {
      setTypingUsers((prev) => {
        const updated = new Set(prev);
        if (typing.latest!.active) {
          updated.add(typing.latest!.sender || 'Someone');
        } else {
          updated.delete(typing.latest!.sender || 'Someone');
        }
        return updated;
      });
    }
  }, [typing.latest]);

  // Send message handler
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputValue, timestamp });
      setMessages((prev) => [...prev, { sender: props.currentUser, text: inputValue, timestamp }]);
      setInputValue('');
      scrollToBottom();
    }
  }, [inputValue, props.currentUser, sendMessage, scrollToBottom]);

  // Handle Enter key in input
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Format timestamp
  const formatTime = (timestamp?: string) => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  // Group consecutive messages by sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; messages: Array<{ text?: string; timestamp?: string }> }> = [];
    for (const msg of messages) {
      if (groups.length > 0 && groups[groups.length - 1].sender === msg.sender) {
        groups[groups.length - 1].messages.push({ text: msg.text, timestamp: msg.timestamp });
      } else {
        groups.push({ sender: msg.sender, messages: [{ text: msg.text, timestamp: msg.timestamp }] });
      }
    }
    return groups;
  }, [messages]);

  const typingText = Array.from(typingUsers).join(', ') || '';

