                      {group.messages.map((msg, msgIdx) => (
                        <Stack key={msgIdx} direction='horizontal' gap={8} align='end' justify={isCurrentUser ? 'end' : 'start'}>
                          {!isCurrentUser && (
                            <Avatar name={group.sender || 'Unknown'} size='sm' />
                          )}
                          <Card
                            padding={12}
                            radius='md'
                            shadow='sm'
                            style={{
                              backgroundColor: isCurrentUser
                                ? 'var(--ggui-color-primary-600, #0284c7)'
                                : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                              maxWidth: '70%',
                              wordWrap: 'break-word',
                            }}
                          >
                            {msgIdx === 0 && !isCurrentUser && (
                              <Text variant='label' color={isCurrentUser ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}>
                                {group.sender || 'Unknown'}
                              </Text>
                            )}
                            <Text
                              variant='body'
                              color={isCurrentUser ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                            >
                              {msg.text}
                            </Text>
                            <Text
                              variant='caption'
                              color={isCurrentUser ? 'rgba(255, 255, 255, 0.7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                              align='right'
                            >
                              {state.formatTime(msg.timestamp)}
                            </Text>
                          </Card>
                        </Stack>
                      ))}
                    </Stack>
                  );
                })}
                <div ref={state.messagesEndRef} />
              </>
            )}
          </Box>

          <Divider orientation='horizontal' margin={0} />

          {/* INPUT AREA */}
          <Stack direction='horizontal' gap={8} padding={16} align='end'>
            <TextArea
              label='Message input'
              placeholder='Type your message... (Shift+Enter for newline)'
              value={state.inputValue}
              onChange={state.setInputValue}
              onKeyDown={state.handleKeyDown}
              rows={2}
              disabled={false}
              style={{ flex: 1 }}
            />
            <Button
              variant='primary'
              size='md'
              onClick={state.handleSendMessage}
              disabled={!state.inputValue.trim()}
            >
              Send
            </Button>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
}

