import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion, MotionKeyframes } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Format price as currency with 2 decimals
function formatPrice(price: number | undefined): string {
  if (price === undefined) return 'N/A';
  return `$${price.toFixed(2)}`;
}

// Determine color based on change direction
function getChangeColor(change: number | undefined): string {
  if (change === undefined) return 'var(--ggui-color-onSurfaceVariant, #52525b)';
  return change >= 0 ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)';
}

// Get arrow icon for change direction
function getArrowIcon(change: number | undefined): string {
  if (change === undefined) return '−';
  return change >= 0 ? '▲' : '▼';
}

// Stock card component with animation on update
function StockCard({ stock, isUpdating }: { stock: { symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }; isUpdating: boolean }) {
  const changeColor = getChangeColor(stock.change);
  const borderColor = stock.change !== undefined && stock.change >= 0 ? 'var(--ggui-color-success-200, #bbf7d0)' : stock.change !== undefined && stock.change < 0 ? 'var(--ggui-color-error-200, #fecaca)' : 'var(--ggui-color-outlineVariant, #e4e4e7)';

  return (
    <>
      <style>{`
        @keyframes stock-flash {
          0% { background-color: var(--ggui-color-primary-100, #e0f2fe); box-shadow: 0 0 12px var(--ggui-color-primary-300, #7dd3fc); }
          100% { background-color: var(--ggui-color-surface, #fafafa); box-shadow: var(--ggui-shape-shadow-sm, 0 1px 2px 0 rgba(0,0,0,0.05)); }
        }
      `}</style>
      <Card
        padding={16}
        shadow="sm"
        border={true}
        radius="lg"
        style={{
          borderColor: borderColor,
          animation: isUpdating ? 'stock-flash 200ms ease-out forwards' : 'none',
          transition: 'border-color 300ms ease-in-out, box-shadow 300ms ease-in-out',
        }}>
        <Stack gap={12}>
          <Stack gap={4}>
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="left">
              {stock.symbol || 'N/A'}
            </Text>
            <Heading level={3} color="var(--ggui-color-onSurface, #18181b)" align="left">
              {stock.name || 'Unknown'}
            </Heading>
          </Stack>

          <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)" align="left">
            {formatPrice(stock.price)}
          </Text>

          <Stack direction="horizontal" gap={8} align="center">
            <Text variant="body" color={changeColor} weight="semibold">
              <span style={{ marginRight: '4px' }}>
                {getArrowIcon(stock.change)}
              </span>
              {stock.change !== undefined ? stock.change.toFixed(2) : 'N/A'} ({stock.changePercent !== undefined ? stock.changePercent.toFixed(2) : 'N/A'}%)
            </Text>
          </Stack>
        </Stack>
      </Card>
    </>
  );
}


function useComponent(props: Props) {
  // Merge initial stocks with live updates
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<string>(new Date().toLocaleTimeString());
  const [updatingSymbols, setUpdatingSymbols] = useState<Set<string>>(new Set());

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // Merge live price updates into displayed stocks
  // Merge live price updates into displayed stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      const updated = priceUpdate.latest;
      setStocks((prevStocks) => {
        const merged = prevStocks.map((stock) => {
          if (stock.symbol && updated.symbol && stock.symbol === updated.symbol) {
            return {
              ...stock,
              price: updated.price !== undefined ? updated.price : stock.price,
              change: updated.change !== undefined ? updated.change : stock.change,
              changePercent: updated.changePercent !== undefined ? updated.changePercent : stock.changePercent,
            };
          }
          return stock;
        });
        return merged;
      });

      // Flash animation on update
      if (updated.symbol) {
        setUpdatingSymbols((prev) => new Set([...prev, updated.symbol]));
        setTimeout(() => {
          setUpdatingSymbols((prev) => {
            const next = new Set(prev);
            next.delete(updated.symbol);
            return next;
          });
        }, 200);
      }

      setLastUpdated(new Date().toLocaleTimeString());
    }
  }, [priceUpdate.latest]);

  // Update timestamp on market status events
  useEffect(() => {
    if (marketStatus.latest?.timestamp) {
      const eventDate = new Date(marketStatus.latest.timestamp);
      setLastUpdated(eventDate.toLocaleTimeString());
    }
  }, [marketStatus.latest]);
  return { stocks, lastUpdated, updatingSymbols, marketStatus };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const marketIsOpen = state.marketStatus.latest?.status === 'open';
  const marketStatusLabel = state.marketStatus.latest?.status || 'unknown';
  const safeStocks = state.stocks && Array.isArray(state.stocks) ? state.stocks : [];
  const updatingSymbols = state.updatingSymbols instanceof Set ? state.updatingSymbols : new Set();

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="xl" padding={24}>
        <Stack gap={24}>
          {/* HEADER WITH TITLE AND TIMESTAMP */}
          <Stack gap={8}>
            <Stack direction="horizontal" gap={8} justify="between" align="center">
              <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
                Market Watch
              </Heading>
              <Stack gap={4} align="end">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Last Updated
                </Text>
                <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)" weight="semibold">
                  {state.lastUpdated}
                </Text>
              </Stack>
            </Stack>
            <Stack direction="horizontal" gap={8} align="center">
              <Badge variant={marketIsOpen ? 'success' : 'default'} size="sm" pill>
                {marketStatusLabel.charAt(0).toUpperCase() + marketStatusLabel.slice(1)}
              </Badge>
            </Stack>
          </Stack>

          {/* STOCK CARDS GRID - RESPONSIVE: 3 PER ROW ON DESKTOP, 1 ON MOBILE */}
          <Stack gap={16}>
            <style>{`
              @media (max-width: 1023px) {
                .stock-grid { display: grid; grid-template-columns: 1fr; gap: var(--ggui-spacing-4, 16px); }
              }
              @media (min-width: 1024px) {
                .stock-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: var(--ggui-spacing-4, 16px); }
              }
            `}</style>
            <div className="stock-grid">
              {safeStocks.length > 0 ? (
                safeStocks.map((stock, idx) => (
                  <StockCard
                    key={stock.symbol || `stock-${idx}`}
                    stock={stock}
                    isUpdating={updatingSymbols.has(stock.symbol || '')}
                  />
                ))
              ) : (
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  No stocks to display
                </Text>
              )}
            </div>
          </Stack>
        </Stack>
      </Container>
    </>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// place any helper functions or sub-components above Component

function useComponent(props: Props) {
  // State for the wizard
  const [currentStep, setCurrentStep] = useState(1);
  const [profile, setProfile] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || props.avatarOptions[0] || '',
    role: props.initialProfile.role || '',
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });

  // Validation state
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Email validation
  const isValidEmail = useCallback((email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }, []);

  // Validation for current step
  const validateStep = useCallback((step: number): boolean => {
    const newErrors: Record<string, string> = {};

    if (step === 1) {
      if (!profile.name.trim()) {
        newErrors.name = 'Name is required';
      }
      if (!profile.email.trim()) {
        newErrors.email = 'Email is required';
      } else if (!isValidEmail(profile.email)) {
        newErrors.email = 'Please enter a valid email address';
      }
      if (!profile.avatar) {
        newErrors.avatar = 'Please select an avatar';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [profile.name, profile.email, profile.avatar, isValidEmail]);

  // Check if current step is valid (for button disable state)
  const isStepValid = useMemo(() => {
    if (currentStep === 1) {
      return profile.name.trim() !== '' && profile.email.trim() !== '' && isValidEmail(profile.email) && profile.avatar;
    }
    return true;
  }, [currentStep, profile.name, profile.email, profile.avatar, isValidEmail]);

  // Handle next step
  const handleNext = useCallback(() => {
    if (validateStep(currentStep)) {
      setCurrentStep(prev => Math.min(prev + 1, 3));
    }
  }, [currentStep, validateStep]);

  // Handle previous step
  // Handle previous step — preserve errors on step 1 but clear when leaving
  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(prev => Math.max(prev - 1, 1));
      // Only clear errors if moving away from step 1
      if (currentStep !== 1) {
        setErrors({});
      }
    }
  }, [currentStep]);

  // Handle field changes
  const handleFieldChange = useCallback((field: string, value: unknown) => {
    setProfile(prev => ({ ...prev, [field]: value }));
    // Clear error for this field when user starts typing
    if (errors[field]) {
      setErrors(prev => {
        const newErrors = { ...prev };
        delete newErrors[field];
        return newErrors;
      });
    }
  }, [errors]);

  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // Handle complete/submit
  const handleComplete = useCallback(() => {
    complete({
      name: profile.name,
      email: profile.email,
      avatar: profile.avatar,
      role: profile.role,
      emailNotifications: profile.emailNotifications,
      theme: profile.theme,
    });
  }, [profile, complete]);
  return { currentStep, profile, errors, handleNext, handleBack, handleFieldChange, handleComplete, isStepValid };
}
export default function Component(props: Props) {
  const state = useComponent(props);
  const { currentStep, profile, errors, handleNext, handleBack, handleFieldChange, handleComplete, isStepValid } = state;

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        {/* STEP INDICATOR */}
        <Stack gap={12}>
          <Stack direction="horizontal" align="center" justify="between">
            <Heading level={2}>Setup Your Profile</Heading>
            <Text variant="label">Step {currentStep} of 3</Text>
          </Stack>
          {/* Progress bar */}
          <Progress
            value={currentStep}
            max={3}
            variant="default"
            size="md"
          />
        </Stack>

        {/* STEP 1: PROFILE SETUP */}
        {currentStep === 1 && (
          <Card shadow="md" padding={24}>
            <Stack gap={16}>
              <Heading level={3}>Profile Information</Heading>
              <Stack gap={16}>
                <Input
                  label="Name"
                  placeholder="Enter your full name"
                  value={profile.name}
                  onChange={(value) => handleFieldChange('name', value)}
                  error={errors.name}
                  required
                />
                <Input
                  label="Email"
                  type="email"
                  placeholder="Enter your email address"
                  value={profile.email}
                  onChange={(value) => handleFieldChange('email', value)}
                  error={errors.email}
                  required
                />
                <Stack gap={8}>
                  <Text variant="label">Choose Avatar</Text>
                  <Stack direction="horizontal" gap={8} wrap>
                    {props.avatarOptions?.map((emoji) => (
                      <Button
                        key={emoji}
                        variant={profile.avatar === emoji ? 'primary' : 'secondary'}
                        size="lg"
                        onClick={() => handleFieldChange('avatar', emoji)}
                        style={{
                          fontSize: '24px',
                          width: '60px',
                          height: '60px',
                          padding: '8px',
                        }}
                      >
                        {emoji}
                      </Button>
                    ))}
                  </Stack>
                  {errors.avatar && <Text variant="caption" color="var(--ggui-color-error-500, #ef4444)">{errors.avatar}</Text>}
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* STEP 2: PREFERENCES */}
        {currentStep === 2 && (
          <Card shadow="md" padding={24}>
            <Stack gap={16}>
              <Heading level={3}>Your Preferences</Heading>
              <Stack gap={16}>
                <Select
                  label="Role"
                  value={profile.role}
                  onChange={(value) => handleFieldChange('role', value)}
                   options={props.roleOptions?.map(role => ({ value: role, label: role })) || []}
                  placeholder="Select your role"
                />
                <Toggle
                  label="Enable email notifications"
                  checked={profile.emailNotifications}
                  onChange={(value) => handleFieldChange('emailNotifications', value)}
                  size="md"
                />
                <Toggle
                  label="Dark theme"
                  checked={profile.theme === 'dark'}
                  onChange={(value) => handleFieldChange('theme', value ? 'dark' : 'light')}
                  size="md"
                />
              </Stack>
            </Stack>
          </Card>
        )}

        {/* STEP 3: REVIEW & CONFIRM */}
        {currentStep === 3 && (
          <Card shadow="md" padding={24}>
            <Stack gap={16}>
              <Heading level={3}>Review Your Setup</Heading>
              <Divider />
              <Stack gap={12}>
                <Stack gap={4}>
                  <Text variant="label">Name</Text>
                  <Text variant="body">{profile.name}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Email</Text>
                  <Text variant="body">{profile.email}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Avatar</Text>
                  <Text variant="body" size="xl">{profile.avatar}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Role</Text>
                  <Text variant="body">{profile.role || 'Not selected'}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Email Notifications</Text>
                  <Badge variant={profile.emailNotifications ? 'success' : 'secondary'}>
                    {profile.emailNotifications ? 'Enabled' : 'Disabled'}
                  </Badge>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Theme</Text>
                  <Badge variant="default">{profile.theme === 'dark' ? 'Dark' : 'Light'}</Badge>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* NAVIGATION BUTTONS */}
        <Row gap={12} justify="between">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Go Back
          </Button>
          {currentStep < 3 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={!isStepValid}
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleComplete}
            >
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
